const html = document.documentElement.outerHTML;
const url = window.location.href;

// Get snapshot name from Automa variable, fallback to document.title
const uniqueName = automaRefData('variables', 'snapshotName') || document.title;

fetch(automaRefData('variables', '$$supabaseUrl') + '/rest/v1/html_snapshots?on_conflict=nav_name', {
  method: 'POST',
  headers: {
    'apikey': automaRefData('variables', '$$supabaseKey'),
    'Authorization': 'Bearer ' + automaRefData('variables', '$$supabaseKey'),
    'Content-Type': 'application/json',
    'Prefer': 'return=representation,resolution=merge-duplicates'
  },
  body: JSON.stringify({
    nav_name: uniqueName,
    url: url,
    html_content: html
  })
}).then(async (res) => {
  if (!res.ok) {
    const err = await res.text();
    console.error("Supabase Insert Error:", err);
  }
  automaNextBlock();
}).catch((e) => {
  console.error("Fetch Error:", e);
  automaNextBlock();
});
